rs.x = vAngle/3.14 + q28;
uv1=abs(fract(uv1+.5)-.5) ;
rs.y = .1/(.05+length(uv1))+uTime*.5;
rs=abs(fract(rs+.5)-.5) ;

vUv = fract(rs);
uv1 = fract(rs);
vec3 ret1 = texture(sampler_main, vUv) + GetBlur1(vUv);

vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);
hor=abs(fract(hor+.5)-.5) ;
ver=abs(fract(ver+.5)-.5) ;
float dx = GetPixel (vUv-hor) - GetPixel (vUv+hor);
float dy = GetPixel (vUv-ver) - GetPixel (vUv+ver);

vec2 dz = vec2 (dx,dy);
dz=abs(fract(dz+.5)-.5) ;

uv1 = .3*cos(uv1*16) - 4*dz;;
uv1=abs(fract(uv1+.5)-.5) ;
vec3 dots = clamp01(.04/length(uv1));

ret1 = 4*(1+audioLowSmooth)*dots*(.6-ret1);

